// Function to set a cookie
function setCookie(name, value, days) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    const expires = "expires=" + date.toUTCString();
    document.cookie = name + "=" + value + ";" + expires + ";path=/";
}

// Function to get a cookie
function getCookie(name) {
    const nameEQ = name + "=";
    const ca = document.cookie.split(';');
    for(let i = 0; i < ca.length; i++) {
        let c = ca[i];
        while (c.charAt(0) === ' ') c = c.substring(1, c.length);
        if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
    }
    return null;
}

// Function to login
function login(username, password, rememberMe) {
    const passwordHash = hashPassword(password); // Assume hashPassword is a function that hashes the password
    if (authenticate(username, passwordHash)) { // Assume authenticate is a function that verifies user credentials
        if (rememberMe) {
            setCookie('rememberMe', JSON.stringify({ username, passwordHash }), 30);
        }
        // Proceed with login
        console.log('User logged in');
    } else {
        console.log('Invalid credentials');
    }
}

// Function to auto-login
function autoLogin() {
    const rememberMeCookie = getCookie('rememberMe');
    if (rememberMeCookie) {
        const { username, passwordHash } = JSON.parse(rememberMeCookie);
        if (authenticate(username, passwordHash)) {
            console.log('User auto-logged in');
            return true;
        }
    }
    return false;
}

